  // 4️⃣ Observadores
  watch: {},

  // 5️⃣ Métodos
  methods: {
    // vuex
    ...mapActions('S20242030', [
      'setSleep',
      'loadData',
      'chunkArray',
      'dowloadFile'
    ]),
    // map
    centerGraphics (points) {
      if (!points || points.length === 0) {
        console.warn('No hay puntos para centrar.')
        return
      }

      const lats = points.map(p => Number(p.lat))
      const longs = points.map(p => Number(p.long))

      // 👉 Centrar en todos los puntos
      if (points.length === 1) {
        const point = new Point({
          latitude: lats[0],
          longitude: longs[0]
        })

        this.view.goTo({
          target: point,
          zoom: 15
        })
      } else if (points.length > 1) {
        // Crear extent manual

        const minX = Math.min(...longs)
        const maxX = Math.max(...longs)
        const minY = Math.min(...lats)
        const maxY = Math.max(...lats)

        const extent = new Extent({
          xmin: minX,
          ymin: minY,
          xmax: maxX,
          ymax: maxY,
          spatialReference: { wkid: 4326 }
        })

        const wmExtent = webMercatorUtils.geographicToWebMercator(extent)
        this.view.goTo(wmExtent.expand(1.5), {
          duration: 1000
        })
      }
    },
    removeGraphics (type, item) {
      if (this.graphicsLayer) {
        if (type === 'all') {
          this.graphicsLayer.removeAll()
        }

        if (type === 'one') {
          // const itemToRemove = this.graphicsLayer.graphics.items.find(conditionCallback)
          // this.graphicsLayer.remove(itemToRemove)
        }

        if (type === 'many') {
          const items = this.graphicsLayer.graphics.items.filter(e => { return e.attributes.type === item.type })
          if (items.length) {
            this.graphicsLayer.removeMany(items)
          }
        }
      }
    },
    async drawGraphic (items, color, type) {
      // console.log('drawGraphic() -->', items)
      // Si no existe la capa, créala con zIndex alto
      if (!this.graphicsLayer) {
        this.graphicsLayer = new GraphicsLayer({
          id: 'graphics-layer',
          title: 'Marcadores',
          zIndex: 100
        })
        this.map.add(this.graphicsLayer)
      }

      await this.setSleep(100)

      items.forEach(element => {
        const point = new Point({
          latitude: element.lat,
          longitude: element.long
        })

        let markerSymbol = {}
        if (type === 1) {
          markerSymbol = {
            type: 'simple-marker',
            color: color
          }
        } else if (type === 2 || type === 3) {
          markerSymbol = {
            type: 'picture-marker',
            url: element.icon,
            width: '10px',
            height: '10px'
          }
        }

        const attributes = {
          ...element,
          type
        }

        const pointGraphic = new Graphic({
          geometry: point,
          symbol: markerSymbol,
          attributes: attributes
        })

        this.graphicsLayer.add(pointGraphic)
      })
    },
    async AddGeoJSONLayer (item) {
      // console.log('AddGeoJSONLayer() -->', item)

      const layerOptions = {
        renderer: {
          type: 'simple',
          symbol: {
            type: 'simple-fill',
            color: item.color,
            outline: {
              width: 1.2,
              color: 'gray' // black
            }
          }
        },
        title: 'GeoJSON Layer',
        zIndex: 10 // Asegura que esté debajo de los gráficos
      }

      if (item.type === 'rendered') {
        layerOptions.url = URL.createObjectURL(new Blob([JSON.stringify(item.data)], { type: 'application/json' }))
      } else if (item.type === 'files') {
        layerOptions.url = item.url
        layerOptions.renderer.symbol.outline = {
          width: 1,
          color: 'black' // gray
        }
      }
      const geojsonLayer = new GeoJSONLayer(layerOptions)
      this.map.add(geojsonLayer)
    },

    async renderJson (items) {
      const result = {
        type: 'FeatureCollection',
        name: '',
        crs: { type: 'name', properties: { name: 'urn:ogc:def:crs:OGC:1.3:CRS84' } },
        features: []
      }

      const chunks = await this.chunkArray({ items, chunkSize: 10 }) // carga 10 archivos por bloque
      for (const chunk of chunks) {
        const dataArray = await Promise.all(chunk.map(item => this.loadData(item.url)))
        dataArray.forEach(data => {
          if (data.features) result.features.push(...data.features)
        })
      }

      return result
    },
    async loadMunicipios () {
      // Cargar todos los datos en paralelo
      const [items1, items2, items3] = await Promise.all([
        this.loadData(`${process.env.VUE_APP_API_URL}20192024/files/municipios_1.json`),
        this.loadData(`${process.env.VUE_APP_API_URL}20192024/files/municipios_2.json`),
        this.loadData(`${process.env.VUE_APP_API_URL}20192024/files/cedes.json`)
      ])

      // Dibujar los gráficos en orden
      await this.drawGraphic(items1, [16, 188, 97], 1)
      await this.drawGraphic(items2, [9, 72, 109], 1)
      await this.drawGraphic(items3, [], 2)
    },
    async loadLayers () {
      const startTime = performance.now()
      await this.AddGeoJSONLayer({ url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/map_layers/puebla.geojson', color: [130, 130, 130, 0.1], type: 'files' })
      const items = await this.loadData(`${process.env.VUE_APP_API_URL}20192024/files/layers.json`)
      // console.log(items)
      const regions = [
        { region: 'S. NORTE - XICOTEPEC', color: [27, 94, 32, 0.5] },
        { region: 'S. NORTE - ZACATLÁN', color: [118, 173, 14, 0.5] },
        { region: 'S. NORORIENTAL', color: [222, 125, 55, 0.5] },
        { region: 'V. SERDÁN', color: [12, 145, 56, 0.5] },
        { region: 'ANGELOPOLIS', color: [14, 139, 173, 0.5] },
        { region: 'V. ATLIXCO Y MATAMOROS', color: [14, 139, 173, 0.5] },
        { region: 'MIXTECA', color: [239, 83, 80, 0.5] },
        { region: 'TEHUACAN', color: [173, 43, 14, 0.5] },
        { region: 'S. NEGRA', color: [173, 14, 93, 0.5] }
      ]

      await Promise.all(regions.map(async region => {
        const regionItems = items.filter(e => e.region === region.region)
        const jsonRegion = await this.renderJson(regionItems)
        await this.AddGeoJSONLayer({ data: jsonRegion, color: region.color, type: 'rendered' })
      }))

      // await this.loadMunicipios()
      const endTime = performance.now()
      console.log(`Total time for fetch: ${((endTime - startTime) / 1000).toFixed(2)} seconds --> getComponents()`)

      // const data = await this.loadData(`${process.env.VUE_APP_API_URL}20192024/files/cedes.json`)
      // console.log(data)
      // await this.drawGraphic(data, [], 2)
    },

    async initMap () {
      this.map = new Map({
        basemap: this.vector[0] // 'streets-navigation-vector'
      })

      this.view = new MapView({
        container: this.$refs.mapView,
        map: this.map,
        center: [-97.74, 19.30], // coordenadas aproximadas de Puebla
        zoom: 7
      })

      await this.view.when() // Esperar a que la vista esté lista antes de agregar el componente
      // await this.view.when(() => { this.dialog_loader.actived = false })
      await this.view.when(() => {
        if (this.view.ready) {
          // console.log('La vista está lista para usarse.')
          // Puedes llamar a funciones como goTo, agregar capas, etc.
        }
      })

      this.WatchExpand = new Expand({
        view: this.view,
        content: document.getElementById('InfoMap'),
        group: 'top-right',
        visible: false,
        focusTrapDisabled: true
      })
      this.view.ui.add(this.WatchExpand, 'top-right')

      this.stopWatchHandle = reactiveUtils.watch(
        () => this.view.updating, // 🔹 propiedad reactiva
        async (updating) => {
          if (!updating) {
            await this.setSleep(1500) // 🔸 esperamos un poco para asegurar que todo terminó de renderizar
            this.dialog_loader.actived = false
          }
        }
      )

      this.view.on('double-click', (event) => { //  click, double-click, pointer-move, drag, hold, immediate-click
        this.view.hitTest(event).then((response) => {
          if (response.results.length) {
            const graphic = response.results[0].graphic
            if (graphic.symbol) {
              // console.log('double-click --> ', graphic.attributes)
              this.GetData_TownHall(graphic.attributes.Id)

              // const newPoint = {
              //   lat: graphic.geometry.latitude,
              //   long: graphic.geometry.longitude,
              //   icon: 'assets/20192024/files/point.png'
              // }

              // this.drawGraphic([newPoint], [], 3)
            }
          }
        })
      })

      // await this.loadLayers()
      await this.AddGeoJSONLayer({ url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/map_layers/puebla.geojson', color: [130, 130, 130, 0.1], type: 'files' })
    },
    // vue -----------------------------------------------------------------------------------------------------------------------
    srcMultimedia (file) {
      const url = `${process.env.VUE_APP_MULTIMEDIA}20192024/${file}`
      return url
    },
    setClass (column, items) {
      if (items.includes(column)) {
        return 'value-table'
      } else {
        return 'desc-table'
      }
    },
    Files () {
      const FILES = {
        1: () => { this.dowloadFile({ fileName: 'INDICADORES-ECONOMIA.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/1.ECONOMIA.xlsx' }) },
        2: () => { this.dowloadFile({ fileName: 'INDICADORES-MIGRACION.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/2.MIGRACION.xlsx' }) },
        3: () => { this.dowloadFile({ fileName: 'INDICADORES-INFRAESTRUCTURA.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/3.INFRAESTRUCTURA.xlsx' }) },
        4: () => { this.dowloadFile({ fileName: 'INDICADORES-GOBERNANZA.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/4.GOBERNANZA.xlsx' }) },
        5: () => { this.dowloadFile({ fileName: 'INDICADORES-MEDIO-AMBIENTE.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/5.MEDIO-AMBIENTE.xlsx' }) },
        6: () => { this.dowloadFile({ fileName: 'INDICADORES-SALUD.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/6.SALUD.xlsx' }) },
        7: () => { this.dowloadFile({ fileName: 'INDICADORES-CULTURA.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/7.CULTURA.xlsx' }) },
        8: () => { this.dowloadFile({ fileName: 'INDICADORES-JUSTICIA-SEGURIDAD.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/8.JUSTICIA-SEGURIDAD.xlsx' }) },
        9: () => { this.dowloadFile({ fileName: 'INDICADORES-TECNOLOGIA.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/9.TECNOLOGIA.xlsx' }) },
        10: () => { this.dowloadFile({ fileName: 'INDICADORES-LENGUA.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/10.LENGUA.xlsx' }) },
        11: () => { this.dowloadFile({ fileName: 'INDICADORES-EDUCACION.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/11.EDUCACION.xlsx' }) },
        12: () => { this.dowloadFile({ fileName: 'INDICADORES-AFROMEXICANA.xlsx', url: 'https://sdti-ippi.github.io/SIEPI/multimedia/20192024/excel/indicadores/12.AFROMEXICANA.xlsx' }) }
      }

      FILES[this.TownHall.idFile] ? FILES[this.TownHall.idFile]() : alert('¡Archivo no disponible, intente más tarde!')
    },
    async GetData_TownHall (value) {
      try {
        // console.log('GetData_TownHall --> ', value, '-->', this.TownHall.uri)
        let result = {}
        this.dialogData.panels = []

        if (this.TownHall.uri === 'lenguages') {
          // console.log('LENGUAS --> ', this.typeLengua)
          if (this.typeLengua === 'Reg') {
            const Find = this.LenguagesR.find(element => { return element.Id === value })
            const { Id, Lenguas, title } = Find
            const items = Lenguas.map(item => ({
              desc: item.nombre,
              val: parseInt(item.total).toLocaleString('en-US')
            }))
            const table = {
              class: ['val'],
              header: false,
              headers: [
                { text: 'LENGUA', value: 'desc' },
                { text: 'HABLANTES', value: 'val' }
              ],
              items
            }

            result = {
              Id,
              Indicator: 'Lenguas Indígenas en la Region',
              title,
              Table_01: table
            }
          } else if (this.typeLengua === 'Mun') {
            const Find = this.LenguagesM.find(element => { return element.Id === value })
            const { Id, Lenguas, title } = Find
            const items = Lenguas.map(item => ({
              desc: item.nombre,
              val: parseInt(item.total).toLocaleString('en-US')
            }))

            const table = {
              class: ['val'],
              header: false,
              headers: [
                { text: 'LENGUA', value: 'desc' },
                { text: 'HABLANTES', value: 'val' }
              ],
              items
            }
            result = {
              Id,
              Indicator: 'Lenguas Indígenas en el Municipio',
              title,
              Table_01: table
            }
          } else if (this.typeLengua === 'MunLengua') {
            const Find = this.LenguaM.find(element => { return element.Id === value })
            const { Id, Lengua, title, nhablantes } = Find
            const items = [
              { desc: Lengua, val: parseInt(nhablantes).toLocaleString('en-US') }
            ]
            const table = {
              class: ['val'],
              header: false,
              headers: [
                { text: 'LENGUA', value: 'desc' },
                { text: 'HABLANTES', value: 'val' }
              ],
              items
            }

            result = {
              Id,
              Indicator: 'LENGUA',
              title,
              Table_01: table
            }
          }
        } else {
          const url = `${process.env.VUE_APP_API_SERVER}${this.TownHall.uri}?type=findId&id=${value}`
          const response = await axios.get(url)
          if (response.data.status === 200) {
            result = response.data.result
          } else {
            result = {}
          }
        }

        if (result.Id) {
          this.dialogData.actived = true
          this.dialogData.title = result.title
          this.dialogData.indicator = result.Indicator

          if (result.Table_01) {
            const TABLE_01 = new Tables()
            await TABLE_01.setTable(result.Table_01)
            this.dialogData.table_01 = TABLE_01
          }

          const panels = []
          if (result.panels) {
            for (const item of result.panels) {
              let chartTemp = {}
              let table = {}

              if (item.table) {
                const TABLE = new Tables()
                await TABLE.setTable(item.table)
                table = TABLE
              }

              if (item.chart) {
                const CHART = new Charts()
                await CHART.setChart(item.chart, item.table)
                chartTemp = CHART
                // console.log('CHART --> ', item.chart, item.table, CHART)
                // console.log('CHART --> ', CHART)
              }

              const panel = {
                panel_header: item.panel_header || null,
                label: item.label || null,
                table,
                label_chart: item.label_chart || null,
                chart: chartTemp
              }
              panels.push(panel)
            }
          }
          this.dialogData.panels = panels
        }
      } catch (error) {
        console.log(error.response.data)
        console.log(error)
      }
    },
    async setCitas (uri) {
      const find = this.citas.all.find(element => { return element.indicator === uri })
      if (Object.hasOwn(find, 'indicator')) {
        this.citas.items = find.items
        this.citas.img = find.img
      }
    },
    async getCitas () {
      try {
        const url = `${process.env.VUE_APP_API_SERVER}fuentes_info?type=map`
        const response = await axios.get(url)
        if (response.data.status === 200) {
          this.citas.all = response.data.result
        }
      } catch (error) {
        console.log(error.response.data)
        console.log(error)
      }
    },
    async Build_InfoMap (uri, items) {
      this.WatchExpand.visible = true

      const mappings = {
        afromexicana: {
          title: 'Indicadores de los municipios indígenas con presencia Afromexicana',
          idFile: 12,
          formatDesc: (item, x) => { return { desc: `${x}.- ${item.title}: ${parseInt(item.TOTAL).toLocaleString()} P. afromexicanos` } }
        },
        culture: {
          title: 'Indicadores de los municipios indígenas en Cultura',
          idFile: 7,
          formatDesc: (item, x) => { return { desc: `${x}.- ${item.title}: ${parseInt(item.PPA).toLocaleString()} Proporción de población afromexicana` } }
        },
        economy: {
          title: 'Economía - Encuesta Intercensal 2020',
          idFile: 1,
          formatDesc: (item, x) => { return { desc: `${x}.- ${item.title}: ${parseInt(item.Poblacion).toLocaleString()} población` } }
        },
        migration: {
          title: 'Migración, población nacida en otra entidad',
          idFile: 2,
          formatDesc: (item, x) => { return { desc: `${x}.- ${item.title}: ${parseInt(item.PNOE).toLocaleString()} migrantes` } }
        },
        infrastructure: {
          title: 'Infraestructura en los municipios indígenas del estado de Puebla',
          idFile: 3,
          formatDesc: (item, x) => { return { desc: `${x}.- ${item.title}: ${parseInt(item.TV).toLocaleString()} viviendas` } }
        },
        governance: {
          title: 'Gobernabilidad y Gobernanza en los municipios indígenas del estado de Puebla',
          idFile: 4,
          formatDesc: (item, x) => { return { desc: `${x}.- ${item.title}` } }
        },
        environment: {
          title: 'Indicadores de los municipios indígenas en el medio ambiente',
          idFile: 5,
          formatDesc: (item, x) => { return { desc: `${x}.- ${item.title}: ${item.TMA}° media anual` } }
        },
        health: {
          title: 'Indicadores de los municipios indígenas en la salud',
          idFile: 6,
          formatDesc: (item, x) => { return { desc: `${x}.- ${item.title}: ${parseInt(item.Poblacion).toLocaleString()} población` } }
        },
        justice: {
          title: 'Indicadores de los municipios indígenas en Justicia y Seguridad',
          idFile: 8,
          formatDesc: (item, x) => { return { desc: `${x}.- ${item.title}` } }
        },
        technology: {
          title: 'Indicadores de los municipios indígenas en la tecnología',
          idFile: 9,
          formatDesc: (item, x) => { return { desc: `${x}.- ${item.title}` } }
        },
        lenguages: {
          idFile: 10,
          formatDesc: (item, x) => {
            if (this.typeLengua === 'Mun') {
              return { title: 'Indicadores las lenguas por municipio', desc: `${x}.- ${item.title}, ${item.Lenguas.length} lenguas` }
            } else if (this.typeLengua === 'Reg') {
              return { title: 'Indicadores las lenguas por regiones', desc: `${x}.- ${item.title}, ${item.Lenguas.length} lenguas` }
            } else if (this.typeLengua === 'MunLengua') {
              return { title: 'Indicadores por lengua en municipios', desc: `${x}.- ${item.title}, ${parseInt(item.nhablantes).toLocaleString()} hablantes` }
            }

            return ''
          }
        },
        education: {
          title: 'Indicadores de los municipios indígenas en Educación',
          idFile: 11,
          formatDesc: (item, x) => { return { desc: `${x}.- ${item.title}` } }
        }
      }

      if (!mappings[uri]) {
        throw new Error(`Unknown URI: ${uri}`)
      }

      const { title, idFile, formatDesc } = mappings[uri]
      this.TownHall.title = title || ''
      this.TownHall.idFile = idFile || 0

      const newArray = []
      let x = 1
      for (const item of items) {
        const element = formatDesc(item, x)
        if (Object.hasOwn(element, 'title')) {
          this.TownHall.title = element.title
          newArray.push({ Id: item.Id, Desc_: element.desc })
        } else {
          newArray.push({ Id: item.Id, Desc_: element.desc })
        }
        x++
      }

      this.TownHall.items = newArray
      await this.setSleep(100)
      this.WatchExpand.expanded = true
    },
    async getLanguages (color, search, id) {
      this.dialog_loader.actived = true
      let req = []
      let send = false

      try {
        this.typeLengua = search

        const url = `${process.env.VUE_APP_API_SERVER}${this.TownHall.uri}?type=points&search=${search}&id=${id}`
        const response = await axios.get(url)
        if (response.data.status === 200) {
          send = true
          req = response.data.result
        }

        if (req.length) {
          if (search === 'Mun') { // Lenguas que se hablan en los Municipio
            this.LenguagesM = req
          } else if (search === 'Reg') { // Lenguas que se hablan en las Regiones
            this.LenguagesR = req
          } else { // Munucios en donde se hablan una lengua en específico
            this.LenguaM = req
          }
        }

        if (send) {
          await this.removeGraphics('all', { type: 1 })
          await this.drawGraphic(req, color, 1)
          await this.Build_InfoMap(this.TownHall.uri, req)
          await this.setCitas(this.TownHall.uri)
          await this.centerGraphics(req)
        }
      } catch (error) {
        return alert('error: ¡Algo salió mal al buscar datos del indicador!')
      } finally {
        this.dialog_loader.actived = false
      }
    },
    async getMarkers (color, uri, items) {
      // console.log('getMarkers()-->', uri)
      this.dialog_loader.actived = true
      let req = []
      let send = false
      try {
        if (items.length === 0) {
          const url = `${process.env.VUE_APP_API_SERVER}${uri}?type=points`
          const response = await axios.get(url)
          if (response.data.status === 200) {
            send = true
            req = response.data.result
          }
        } else {
          send = true
          req = items
        }

        if (!send) { return }
        const index = this.Indicators.findIndex(item => { return item.uri === uri })
        this.Indicators[index].items = req

        await this.removeGraphics('all', { type: 1 })
        await this.drawGraphic(req, color, 1)
        await this.Build_InfoMap(uri, req)
        await this.setCitas(uri)
        await this.centerGraphics(req)
      } catch (error) {
        console.log(error)
        alert('error: ¡Algo salió mal al buscar datos del indicador!')
        return
      } finally {
        this.dialog_loader.actived = false
      }
    },
    async SltIndocator (element) {
      // console.log('SltIndocator()-->', element)
      this.list_item = element.color
      this.TownHall.search = ''
      this.TownHall.items = []
      this.TownHall.uri = element.uri

      if (element.uri === 'lenguages') {
        const { color, search, idSearch } = element
        await this.getLanguages(color, search, idSearch)
      } else {
        const { color, uri, items } = element
        await this.getMarkers(color, uri, items)
      }
    },
    async getIndicators () {
      const url = `${process.env.VUE_APP_API_SERVER}map?type=items`
      // console.log(url)
      try {
        const response = await axios.get(url)
        if (response.data.status === 200) {
          this.Indicators = response.data.result
        }
      } catch (error) {
        console.log(error)
        console.log(error.response.data)
      }
    }
  },

  // 6️⃣ Ciclo de vida
  beforeCreate () {},
  created () {
    this.dialog_loader.actived = true
    this.dialog_loader.message = 'Por favor espere...'

    this.getIndicators()
    this.getCitas()
  },
  beforeMount () {},
  async mounted () {
    await this.initMap()
  },
  beforeUpdate () {},
  updated () {},
  beforeDestroy () {
    if (this.stopWatchHandle) {
      this.stopWatchHandle.remove()
      this.stopWatchHandle = null
    }

    if (this.view) {
      this.view.destroy()
      this.view = null
    }
  },
  destroyed () { }

  // 7️⃣ Hooks específicos (como de rutas, etc.)
  // beforeRouteEnter() {}, etc.

}
</script>

